// ═══════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════
let currentView  = 'home';
let currentCat   = null;
let currentEntry = null;
let openSections = new Set(['races','classes','backgrounds','spells','feats']);

const SCHOOL_FULL = {'A':'Abjuración','C':'Conjuración','D':'Adivinación',
  'EN':'Encantamiento','EV':'Evocación','I':'Ilusión','N':'Nigromancia','T':'Transmutación'};
const STAT_NAMES  = {STR:'Fuerza',DEX:'Destreza',CON:'Constitución',
  INT:'Inteligencia',WIS:'Sabiduría',CHA:'Carisma'};
function modStr(v){ const m=Math.floor((+v-10)/2); return (m>=0?'+':'')+m; }
function profBonus(lv){ return lv>=17?6:lv>=13?5:lv>=9?4:lv>=5?3:2; }

// ═══════════════════════════════════════════
// SIDEBAR NAV
// ═══════════════════════════════════════════
function buildNav(){
  const sections = [
    { id:'races',       icon:'🧝', label:'Razas',       items:DATA.races,       key:'n' },
    { id:'classes',     icon:'⚔',  label:'Clases',      items:DATA.classes,     key:'n' },
    { id:'backgrounds', icon:'📜', label:'Trasfondos',  items:DATA.backgrounds, key:'n' },
    { id:'spells',      icon:'✨', label:'Hechizos',    items:DATA.spells,      key:'n' },
    { id:'feats',       icon:'⭐', label:'Dotes',       items:DATA.feats,       key:'n' },
  ];
  const el = document.getElementById('nav-tree');
  el.innerHTML = sections.map(s=>`
    <div class="nav-section">
      <div class="nav-label ${openSections.has(s.id)?'open':''}" onclick="toggleSection('${s.id}')">
        ${s.icon} ${s.label}
        <span class="count">${s.items.length}</span>
        <span class="arrow">▶</span>
      </div>
      <div class="nav-items ${openSections.has(s.id)?'open':''}" id="nav-${s.id}">
        ${s.items.map((item,i)=>`
          <div class="nav-item" id="ni-${s.id}-${i}" onclick="openEntry('${s.id}',${i})">
            ${item[s.key]}
          </div>`).join('')}
      </div>
    </div>`).join('');
}

function toggleSection(id){
  if(openSections.has(id)) openSections.delete(id);
  else openSections.add(id);
  buildNav();
  if(currentCat===id) setActiveNav(id, currentEntry);
}

function setActiveNav(cat, idx){
  document.querySelectorAll('.nav-item').forEach(el=>el.classList.remove('active'));
  if(idx!==null){
    const el=document.getElementById(`ni-${cat}-${idx}`);
    if(el){ el.classList.add('active'); el.scrollIntoView({block:'nearest'}); }
  }
}

// ═══════════════════════════════════════════
// ROUTING
// ═══════════════════════════════════════════
function showHome(){
  currentView='home'; currentCat=null; currentEntry=null;
  document.querySelectorAll('.nav-item').forEach(el=>el.classList.remove('active'));
  document.getElementById('content').innerHTML = renderHome();
}

function openList(cat){
  currentView='list'; currentCat=cat; currentEntry=null;
  document.getElementById('content').innerHTML = renderList(cat);
  document.getElementById('main').scrollTop=0;
}

function openEntry(cat, idx){
  currentView='entry'; currentCat=cat; currentEntry=idx;
  setActiveNav(cat, idx);
  const renders = {
    races: renderRaceEntry, classes: renderClassEntry,
    backgrounds: renderBgEntry, spells: renderSpellEntry, feats: renderFeatEntry
  };
  document.getElementById('content').innerHTML = (renders[cat]||renderFallback)(DATA[cat][idx], idx, cat);
  document.getElementById('main').scrollTop=0;
  // Update hash
  window.location.hash = cat+'/'+idx;
}

// ═══════════════════════════════════════════
// HOME
// ═══════════════════════════════════════════
function renderHome(){
  return `<div class="home">
    <div class="home-title">Compendio del Jugador</div>
    <div class="home-sub">Referencia completa de razas, clases, trasfondos, hechizos y dotes para D&amp;D 5e</div>
    <div class="category-grid">
      <div class="cat-card c-races" onclick="openList('races')">
        <div class="cat-icon">🧝</div>
        <div class="cat-name">Razas</div>
        <div class="cat-count">${DATA.races.length} opciones</div>
      </div>
      <div class="cat-card c-classes" onclick="openList('classes')">
        <div class="cat-icon">⚔</div>
        <div class="cat-name">Clases</div>
        <div class="cat-count">${DATA.classes.length} clases</div>
      </div>
      <div class="cat-card c-backgrounds" onclick="openList('backgrounds')">
        <div class="cat-icon">📜</div>
        <div class="cat-name">Trasfondos</div>
        <div class="cat-count">${DATA.backgrounds.length} opciones</div>
      </div>
      <div class="cat-card c-spells" onclick="openList('spells')">
        <div class="cat-icon">✨</div>
        <div class="cat-name">Hechizos</div>
        <div class="cat-count">${DATA.spells.length} hechizos</div>
      </div>
      <div class="cat-card c-feats" onclick="openList('feats')">
        <div class="cat-icon">⭐</div>
        <div class="cat-name">Dotes</div>
        <div class="cat-count">${DATA.feats.length} dotes</div>
      </div>
    </div>
  </div>`;
}

// ═══════════════════════════════════════════
// LIST VIEWS
// ═══════════════════════════════════════════
function renderList(cat){
  if(cat==='spells') return renderSpellList();
  const CONFIGS = {
    races:       {title:'Razas',       sub:'Elige tu herencia. La raza define tus rasgos innatos y bonificadores de atributo.', icon:'🧝'},
    classes:     {title:'Clases',      sub:'Tu vocación de aventurero. Define tus capacidades en combate, magia y exploración.', icon:'⚔'},
    backgrounds: {title:'Trasfondos',  sub:'Lo que eras antes de convertirte en aventurero. Pericias, idiomas y rasgos de personalidad.', icon:'📜'},
    feats:       {title:'Dotes',       sub:'Habilidades especiales que puedes adquirir al subir de nivel.', icon:'⭐'},
  };
  const cfg = CONFIGS[cat];
  const items = DATA[cat];
  return `<div class="list-view">
    <div class="list-title">${cfg.icon} ${cfg.title}</div>
    <div class="list-subtitle">${cfg.sub}</div>
    <div class="list-grid">
      ${items.map((item,i)=>renderListCard(cat,item,i)).join('')}
    </div>
  </div>`;
}

function renderListCard(cat,item,i){
  if(cat==='races'){
    const bonuses=Object.entries(item.bonus||{}).map(([k,v])=>`+${v} ${k}`).join(', ');
    return `<div class="list-card" onclick="openEntry('${cat}',${i})">
      <div class="list-card-name">${item.n}</div>
      <div class="list-card-sub">Vel. ${item.spd}ft</div>
      ${bonuses?`<div class="list-card-tags"><span class="tag tag-gold">${bonuses}</span></div>`:''}
    </div>`;
  }
  if(cat==='classes'){
    const sp=item.spellcaster?'<span class="tag tag-purple">Magia</span>':'';
    return `<div class="list-card" onclick="openEntry('${cat}',${i})">
      <div class="list-card-name">${item.n}</div>
      <div class="list-card-sub">d${item.hd} HP · ${item.saves?.join('/')||'?'}</div>
      <div class="list-card-tags"><span class="tag tag-red">d${item.hd}</span>${sp}</div>
    </div>`;
  }
  if(cat==='backgrounds'){
    return `<div class="list-card" onclick="openEntry('${cat}',${i})">
      <div class="list-card-name">${item.n}</div>
      ${item.skills?.length?`<div class="list-card-sub">${item.skills.join(', ')}</div>`:''}
    </div>`;
  }
  if(cat==='feats'){
    return `<div class="list-card" onclick="openEntry('${cat}',${i})">
      <div class="list-card-name">${item.n}</div>
      ${item.pr?`<div class="list-card-sub">Prereq: ${item.pr}</div>`:''}
    </div>`;
  }
  return `<div class="list-card" onclick="openEntry('${cat}',${i})"><div class="list-card-name">${item.n}</div></div>`;
}

function renderSpellList(){
  const lvlFilter = [...new Set(DATA.spells.map(s=>s.lv))].sort((a,b)=>+a-+b);
  const scFilter  = [...new Set(DATA.spells.map(s=>s.sc).filter(Boolean))].sort();
  const clsFilter = [...new Set(DATA.spells.flatMap(s=>(s.cl||'').split(',').map(c=>c.trim())).filter(Boolean))].sort();
  return `<div class="list-view">
    <div class="list-title">✨ Hechizos</div>
    <div class="list-subtitle">Magia arcana y divina al alcance de tu mano. ${DATA.spells.length} hechizos disponibles.</div>
    <div class="list-filters">
      <input class="filter-sel" id="spell-q" placeholder="Buscar..." oninput="filterSpells()" style="font-family:'Crimson Text',serif;font-size:14px;min-width:160px;appearance:auto">
      <select class="filter-sel" id="spell-lv" onchange="filterSpells()">
        <option value="">Todos los niveles</option>
        <option value="0">Trucos (Nv. 0)</option>
        ${lvlFilter.filter(l=>l!=='0').map(l=>`<option value="${l}">Nivel ${l}</option>`).join('')}
      </select>
      <select class="filter-sel" id="spell-sc" onchange="filterSpells()">
        <option value="">Toda escuela</option>
        ${scFilter.map(sc=>`<option value="${sc}">${sc}</option>`).join('')}
      </select>
      <select class="filter-sel" id="spell-cls" onchange="filterSpells()">
        <option value="">Todas las clases</option>
        ${clsFilter.map(c=>`<option value="${c}">${c}</option>`).join('')}
      </select>
    </div>
    <div id="spell-list-items"></div>
  </div>`;
}

function filterSpells(){
  const q   = (document.getElementById('spell-q')?.value||'').toLowerCase();
  const lv  = document.getElementById('spell-lv')?.value||'';
  const sc  = document.getElementById('spell-sc')?.value||'';
  const cls = document.getElementById('spell-cls')?.value||'';
  const filtered = DATA.spells.filter(s=>{
    if(q && !s.n.toLowerCase().includes(q)) return false;
    if(lv!=='' && s.lv!==lv) return false;
    if(sc && s.sc!==sc) return false;
    if(cls && !(s.cl||'').includes(cls)) return false;
    return true;
  });
  const idx = DATA.spells.indexOf.bind(DATA.spells);
  const el = document.getElementById('spell-list-items');
  if(!el) return;
  el.innerHTML = filtered.length===0
    ? `<div style="text-align:center;padding:30px;color:var(--cream-m);font-style:italic">Sin resultados.</div>`
    : filtered.map(s=>{
        const i=DATA.spells.indexOf(s);
        const lvLabel=s.lv==='0'?'Truco':'Nv.'+s.lv;
        return `<div class="spell-list-item" onclick="openEntry('spells',${i})">
          <div>
            <div class="sli-name">${s.n}</div>
            <div class="sli-sub">${s.ti||''}${s.ra?' · '+s.ra:''}</div>
          </div>
          <div class="sli-badges">
            <span class="tag tag-purple" style="font-size:8px">${lvLabel}</span>
            ${s.sc?`<span class="tag tag-gray" style="font-size:8px">${s.sc}</span>`:''}
          </div>
        </div>`;
      }).join('');
}

// ═══════════════════════════════════════════
// ENTRY RENDERERS
// ═══════════════════════════════════════════
function breadcrumb(catLabel, catId, name){
  return `<div class="entry-breadcrumb">
    <span class="breadcrumb-link" onclick="showHome()">Inicio</span>
    <span class="breadcrumb-sep">›</span>
    <span class="breadcrumb-link" onclick="openList('${catId}')">${catLabel}</span>
    <span class="breadcrumb-sep">›</span>
    <span>${name}</span>
  </div>`;
}

function navButtons(cat, idx){
  const items = DATA[cat];
  const prev = idx>0 ? `<span class="breadcrumb-link" onclick="openEntry('${cat}',${idx-1})">‹ ${items[idx-1].n}</span>` : '';
  const next = idx<items.length-1 ? `<span class="breadcrumb-link" onclick="openEntry('${cat}',${idx+1})">${items[idx+1].n} ›</span>` : '';
  return `<div style="display:flex;justify-content:space-between;margin-top:32px;padding-top:16px;border-top:1px solid var(--border);font-family:'Cinzel',serif;font-size:10px;letter-spacing:.5px">${prev}<span></span>${next}</div>`;
}

// ── RACE ──
function renderRaceEntry(r, idx){
  const bonuses=Object.entries(r.bonus||{}).map(([k,v])=>
    `<span class="tag tag-gold">${STAT_NAMES[k]||k} +${v}</span>`).join('');
  return `<div class="entry">
    ${breadcrumb('Razas','races',r.n)}
    <div class="entry-hero">
      <div class="entry-name">${r.n}</div>
      <div class="entry-type">RAZA</div>
      <div class="entry-tags">
        ${bonuses||'<span class="tag tag-gray">Sin bonificadores de atributo</span>'}
        <span class="tag tag-blue">Vel. ${r.spd}ft</span>
        ${r.sz?`<span class="tag tag-gray">${{T:'Diminuto',S:'Pequeño',M:'Mediano',L:'Grande',H:'Enorme',G:'Gargantuesco'}[r.sz]||r.sz}</span>`:''}
      </div>
    </div>
    ${r.abi?`<div class="section">
      <div class="section-title">Incremento de puntuación de característica</div>
      <div class="body-text">${r.abi}</div>
    </div>`:''}
    ${r.lng?`<div class="section">
      <div class="section-title">Idiomas</div>
      <div class="body-text">${r.lng}</div>
    </div>`:''}
    ${(r.traits||[]).length?`<div class="section">
      <div class="section-title">Rasgos raciales</div>
      ${r.traits.map(t=>`<div class="feature">
        <div class="feature-name">${t.n}</div>
        ${(t.tx||[]).map(line=>`<div class="feature-text">${line}</div>`).join('')}
      </div>`).join('')}
    </div>`:''}
    ${navButtons('races',idx)}
  </div>`;
}

// ── CLASS ──
function renderClassEntry(c, idx){
  // Group features by level
  const levelGroups = c.levels||[];
  const allFeatures = levelGroups.flatMap(lv=>
    (lv.features||[]).map(f=>({...f, lv:lv.lv})));

  const tableRows = levelGroups.map(lv=>{
    const feats=(lv.features||[]).map(f=>f.n).join(', ');
    return `<tr class="${lv.lv%4===0?'highlight':''}">
      <td class="lv-num">${lv.lv}</td>
      <td>+${profBonus(lv.lv)}</td>
      <td>${lv.slots||'—'}</td>
      <td>${feats||'—'}</td>
    </tr>`;
  }).join('');

  return `<div class="entry">
    ${breadcrumb('Clases','classes',c.n)}
    <div class="entry-hero">
      <div class="entry-name">${c.n}</div>
      <div class="entry-type">CLASE</div>
      <div class="entry-tags">
        <span class="tag tag-red">d${c.hd} Dado de golpe</span>
        ${(c.saves||[]).map(s=>`<span class="tag tag-gold">ST ${s}</span>`).join('')}
        ${c.spellcaster?'<span class="tag tag-purple">✨ Lanzador de hechizos</span>':''}
      </div>
    </div>
    ${c.prof?`<div class="section">
      <div class="section-title">Competencias</div>
      <div class="body-text">${c.prof}</div>
    </div>`:''}
    ${c.equip?`<div class="section">
      <div class="section-title">Equipo inicial</div>
      <div class="body-text">${c.equip}</div>
    </div>`:''}
    <div class="section">
      <div class="section-title">Tabla de progresión</div>
      <div style="overflow-x:auto">
        <table class="level-table">
          <thead><tr>
            <th>NIV.</th><th>PROF.</th><th>ESPACIOS</th><th>RASGOS</th>
          </tr></thead>
          <tbody>${tableRows}</tbody>
        </table>
      </div>
    </div>
    <div class="section">
      <div class="section-title">Rasgos de clase</div>
      ${allFeatures.map(f=>`<div class="feature gold-left">
        <div class="feature-name">
          ${f.n}
          <span class="level-badge">NIVEL ${f.lv}</span>
        </div>
        ${(f.tx||[]).map(line=>`<div class="feature-text">${line}</div>`).join('')}
      </div>`).join('')}
    </div>
    ${navButtons('classes',idx)}
  </div>`;
}

// ── BACKGROUND ──
function renderBgEntry(b, idx){
  return `<div class="entry">
    ${breadcrumb('Trasfondos','backgrounds',b.n)}
    <div class="entry-hero">
      <div class="entry-name">${b.n}</div>
      <div class="entry-type">TRASFONDO</div>
      <div class="entry-tags">
        ${(b.skills||[]).map(s=>`<span class="tag tag-green">${s}</span>`).join('')}
      </div>
    </div>
    ${b.prof?`<div class="section">
      <div class="section-title">Competencias</div>
      <div class="body-text">${b.prof}</div>
    </div>`:''}
    ${(b.traits||[]).length?`<div class="section">
      <div class="section-title">Rasgos</div>
      ${b.traits.map(t=>`<div class="feature green-left">
        <div class="feature-name">${t.n}</div>
        ${(t.tx||[]).map(line=>`<div class="feature-text">${line}</div>`).join('')}
      </div>`).join('')}
    </div>`:''}
    ${navButtons('backgrounds',idx)}
  </div>`;
}

// ── SPELL ──
function renderSpellEntry(s, idx){
  const lvLabel=s.lv==='0'?'Truco (Nivel 0)':`Nivel ${s.lv}`;
  const classes=(s.cl||'').split(',').map(c=>c.trim()).filter(Boolean);
  return `<div class="entry">
    ${breadcrumb('Hechizos','spells',s.n)}
    <div class="entry-hero">
      <div class="entry-name">${s.n}</div>
      <div class="spell-header">
        <span class="spell-school">${lvLabel} de ${s.sc||'?'}</span>
      </div>
      <div class="entry-tags">
        <span class="tag tag-purple">${lvLabel}</span>
        ${s.sc?`<span class="tag tag-blue">${s.sc}</span>`:''}
        ${s.dice?`<span class="tag tag-red">${s.dice}</span>`:''}
      </div>
    </div>
    <div class="info-grid" style="grid-template-columns:1fr 1fr">
      ${[['Tiempo de lanzamiento',s.ti],['Alcance',s.ra],
         ['Componentes',s.co],['Duración',s.du]]
        .filter(([,v])=>v)
        .map(([l,v])=>`<div class="info-row"><span class="info-label">${l}</span><span class="info-val">${v}</span></div>`)
        .join('')}
    </div>
    <div class="section">
      <div class="section-title">Descripción</div>
      ${(s.tx||[]).map(line=>`<div class="body-text">${line}</div>`).join('')}
    </div>
    ${classes.length?`<div class="section">
      <div class="section-title">Clases</div>
      <div class="entry-tags">${classes.map(c=>`<span class="tag tag-gray">${c}</span>`).join('')}</div>
    </div>`:''}
    ${navButtons('spells',idx)}
  </div>`;
}

// ── FEAT ──
function renderFeatEntry(f, idx){
  return `<div class="entry">
    ${breadcrumb('Dotes','feats',f.n)}
    <div class="entry-hero">
      <div class="entry-name">${f.n}</div>
      <div class="entry-type">DOTE</div>
      ${f.pr?`<div class="entry-tags"><span class="tag tag-red">Requisito: ${f.pr}</span></div>`:''}
    </div>
    <div class="section">
      <div class="section-title">Descripción</div>
      ${(f.tx||[]).map(line=>`<div class="body-text">${line}</div>`).join('')}
    </div>
    ${navButtons('feats',idx)}
  </div>`;
}

function renderFallback(item){ return `<div class="entry"><div class="entry-name">${item?.n||'?'}</div></div>`; }

// ═══════════════════════════════════════════
// GLOBAL SEARCH
// ═══════════════════════════════════════════
function globalSearch(q){
  if(!q||q.length<2){ buildNav(); return; }
  const lq=q.toLowerCase();
  const results=[];
  ['races','classes','backgrounds','feats','spells'].forEach(cat=>{
    DATA[cat].forEach((item,i)=>{
      if(item.n.toLowerCase().includes(lq)) results.push({cat,i,n:item.n});
    });
  });
  const el=document.getElementById('nav-tree');
  if(!results.length){ el.innerHTML=`<div style="padding:16px;font-size:13px;color:var(--cream-m);font-style:italic">Sin resultados para "${q}"</div>`; return; }
  el.innerHTML=`<div style="padding:10px 0">
    <div style="font-family:'Cinzel',serif;font-size:9px;letter-spacing:1px;color:var(--purple-d);padding:6px 16px">${results.length} RESULTADOS</div>
    ${results.slice(0,40).map(r=>`
      <div class="nav-item" onclick="openEntry('${r.cat}',${r.i})">${r.n}</div>`).join('')}
    ${results.length>40?`<div style="padding:6px 16px;font-size:11px;color:var(--cream-m)">...y ${results.length-40} más. Refina la búsqueda.</div>`:''}
  </div>`;
}

// ═══════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════
buildNav();
// Check URL hash for deep link
const hash = window.location.hash.slice(1);
if(hash) {
  const [cat, idxStr] = hash.split('/');
  const idx = parseInt(idxStr);
  if(cat && !isNaN(idx) && DATA[cat]?.[idx]) {
    openEntry(cat, idx);
  } else { showHome(); }
} else { showHome(); }

// Spell list needs init after render
document.getElementById('main').addEventListener('click', e => {
  if(e.target.id==='spell-q') { setTimeout(filterSpells, 0); }
});
